import express from "express";
import nunjucks from "nunjucks";
import { mapRepoFromStorageToUi, getOrgs } from "./utils/index.js";
import { sortByType } from "./utils/sorting.js";
import { TowtruckDatabase } from "./db/index.js";
import { handleWebhooks } from "./webhooks/index.js";

nunjucks.configure({
  autoescape: true,
  watch: true,
});

const httpServer = express();
httpServer.use(handleWebhooks);

httpServer.get("/", (request, response) => {
  const db = new TowtruckDatabase();
  const persistedRepoData = db.getAllRepositories();
  const orgs = getOrgs(persistedRepoData);

  const template = nunjucks.render("home.njk", { orgs });

  return response.end(template);
});

httpServer.get("/:org", (request, response) => {
  const { org } = request.params;
  const db = new TowtruckDatabase();
  const persistedRepoData = db.getAllRepositoriesForOrg(org);
  const persistedLifetimeData = db.getAllDependencies();

  const reposForUi = mapRepoFromStorageToUi(persistedRepoData, persistedLifetimeData);

  const { sortDirection, sortBy } = request.query;

  const template = nunjucks.render("index.njk", {
    sortBy,
    sortDirection,
    ...reposForUi,
    org,
    repos: sortByType(reposForUi.repos, sortDirection, sortBy),
  });

  return response.end(template);
});

const PORT = process.env.PORT || 3000;
httpServer.listen(PORT, () => {
  console.info(`Server is running on port ${PORT}`);
});

import express from "express";
import nunjucks from "nunjucks";
import { mapRepoFromStorageToUi, getOrgs } from "./utils/index.js";
import { sortByType } from "./utils/sorting.js";
import { filterByAlerts } from "./utils/alertFiltering.js";
import { calculatePagination } from "./utils/pagination.js";
import { TowtruckDatabase } from "./db/index.js";
import { handleWebhooks } from "./webhooks/index.js";

nunjucks.configure({
  autoescape: true,
  watch: true,
});

const httpServer = express();
httpServer.use(handleWebhooks);

httpServer.get("/", (request, response) => {
  const db = new TowtruckDatabase();
  const persistedRepoData = db.getAllRepositories();
  const orgs = getOrgs(persistedRepoData);

  const template = nunjucks.render("home.njk", { orgs });

  return response.end(template);
});

httpServer.get("/:org", (request, response) => {
  const { org } = request.params;
  const db = new TowtruckDatabase();
  const persistedRepoData = db.getAllRepositoriesForOrg(org);
  const persistedLifetimeData = db.getAllDependencies();

  const reposForUi = mapRepoFromStorageToUi(persistedRepoData, persistedLifetimeData);

  const { sortDirection, sortBy, tag, page: pageParam, alertFilter } = request.query;

  const filteredByTag = tag
    ? reposForUi.repos.filter((repo) => repo.topics && repo.topics.includes(tag))
    : reposForUi.repos;

  const filteredByAlerts = filterByAlerts(filteredByTag, alertFilter);
  const sortedRepos = sortByType(filteredByAlerts, sortDirection, sortBy);
  const paginationData = calculatePagination(sortedRepos, pageParam);

  const template = nunjucks.render("index.njk", {
    sortBy,
    sortDirection,
    tag,
    alertFilter,
    ...reposForUi,
    org,
    repos: paginationData.items,
    totalRepos: reposForUi.totalRepos,
    displayedRepos: filteredByAlerts.length,
    currentPage: paginationData.currentPage,
    totalPages: paginationData.totalPages,
    pageNumbers: paginationData.pageNumbers,
    hasPreviousPage: paginationData.hasPreviousPage,
    hasNextPage: paginationData.hasNextPage,
  });

  return response.end(template);
});

const PORT = process.env.PORT || 3000;
httpServer.listen(PORT, () => {
  console.info(`Server is running on port ${PORT}`);
});

{% import "./macros.njk" as macros %}

<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <meta http-equiv="X-UA-Compatible" content="IE=edge" />
    <title>Towtruck</title>
    <meta name="description" content="" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <link href='https://unpkg.com/boxicons@2.1.4/css/boxicons.min.css' rel='stylesheet'>
    <script src="https://cdn.tailwindcss.com"></script>
    <script>tailwind.config = { darkMode: 'class' }</script>
    <script>
      if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        document.documentElement.classList.add('dark');
      }
    </script>
  </head>
  <body class="bg-slate-200 text-slate-900 dark:bg-slate-950 dark:text-slate-100">
    <header class="bg-slate-600 dark:bg-slate-900 text-white">
      <nav class="w-full flex items-center gap-4 p-6 border-b-4 border-slate-700 dark:border-slate-950">
        <a href="/" class="text-slate-300 hover:text-white transition-colors" aria-label="Back to home">
          <i class="bx bx-arrow-back text-2xl"></i>
        </a>
        <h1 class="text-3xl font-bold flex-1">Towtruck</h1>
        <button id="theme-toggle" aria-label="Toggle dark mode"
          class="text-slate-200 hover:text-white transition-colors p-1 rounded-lg hover:bg-slate-500 dark:hover:bg-slate-700">
          <i id="theme-icon" class="bx text-2xl"></i>
        </button>
      </nav>
    </header>

    <div class="container mx-auto flex flex-col mt-6 space-y-6">
      <div class="bg-slate-100 dark:bg-slate-900 rounded-lg border-b-4 border-slate-300 dark:border-slate-950 space-y-4">
        <h2 class="bg-slate-50 dark:bg-slate-800 rounded-t-lg border-b-2 border-slate-200 dark:border-slate-900 text-xl font-bold p-4">{{ org }}</h2>
        <p class="mx-4">
          {% if totalRepos === 1 %}
          There is <span class="font-bold">1</span> repository
          {% else %} 
          There are <span class="font-bold">{{ totalRepos }}</span> repositories
          {% endif %}
          that Towtruck is tracking for <span class="font-bold">{{ org }}</span>.
        </p>
        <!-- Sort toolbar -->
        <div class="mx-4 pb-2">
          <div class="flex flex-wrap items-center gap-2">
            <span class="text-sm font-medium text-slate-500 dark:text-slate-400 mr-1">Sort by:</span>
            {{macros.sortableCardHeader("Open issues", "openIssues", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Open bot PRs", "openBotPrCount", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Open PRs", "openPrCount", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Updated at", "updatedAt", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Most recent PR", "mostRecentPrOpenedAt", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Oldest open PR", "oldestOpenPrOpenedAt", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Most recent issue", "mostRecentIssueOpenedAt", sortDirection, sortBy, "/" + org)}}
            {{macros.sortableCardHeader("Oldest open issue", "oldestOpenIssueOpenedAt", sortDirection, sortBy, "/" + org)}}
          </div>
        </div>

        <!-- Card grid -->
        <div class="mx-4 mb-6 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {% for repo in repos %}
          <div class="bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 flex flex-col shadow-sm">

            <!-- Card header -->
            <div class="p-4 border-b border-slate-100 dark:border-slate-700">
              <div class="flex flex-wrap items-center gap-2">
                <a target="_blank" class="text-lg font-semibold text-slate-600 dark:text-slate-300 hover:underline" href="{{repo.htmlUrl}}">{{ repo.name }}</a>
                {% if repo.language %}
                <span class="text-xs text-{{ repo.languageColor }}-600 dark:text-{{ repo.languageColor }}-400 border-{{ repo.languageColor }}-600 dark:border-{{ repo.languageColor }}-400 border rounded-lg py-0.5 px-2">{{ repo.language }}</span>
                {% endif %}
              </div>

              {% if repo.totalOpenAlerts !== undefined %}
              <div class="flex flex-wrap gap-0 mt-2 text-[0px]">
                {% set id = [repo.name, "alerts", "critical"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.criticalSeverityAlerts, ">", repo.criticalSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-red-600 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "Critical severity alerts")}}</div>
                {% set id = [repo.name, "alerts", "high"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.highSeverityAlerts, ">", repo.highSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-red-500 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "High severity alerts")}}</div>
                {% set id = [repo.name, "alerts", "medium"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.mediumSeverityAlerts, ">", repo.mediumSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-orange-500 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "Medium severity alerts")}}</div>
                {% set id = [repo.name, "alerts", "low"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.lowSeverityAlerts, ">", repo.lowSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-amber-500 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "Low severity alerts")}}</div>
              </div>
              {% else %}
              <p class="mt-1 text-slate-400 text-xs font-light italic">Dependabot alerts disabled</p>
              {% endif %}

              {% if repo.description %}
              <p class="mt-2 text-sm text-slate-700 dark:text-slate-200">{{ repo.description }}</p>
              {% endif %}

              {% if repo.topics.length %}
              <div class="mt-2 flex flex-wrap gap-1">
                {% for topic in repo.topics %}
                <span class="text-xs text-slate-600 dark:text-slate-300 bg-slate-200 dark:bg-slate-900 rounded-full py-0.5 px-2">{{ topic }}</span>
                {% endfor %}
              </div>
              {% endif %}
            </div>

            <!-- Stats grid -->
            <div class="grid grid-cols-2 gap-x-4 gap-y-2 p-4 text-sm border-b border-slate-100 dark:border-slate-700">
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Open issues</span>
                <p class="font-semibold">{{ repo.openIssues }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Open PRs</span>
                <p class="font-semibold">{{ repo.openPrCount }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Bot PRs</span>
                <p class="font-semibold">{{ repo.openBotPrCount }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Updated at</span>
                <p class="font-semibold">{{ repo.updatedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Most recent PR</span>
                <p class="font-semibold">{{ repo.mostRecentPrOpenedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Oldest open PR</span>
                <p class="font-semibold">{{ repo.oldestOpenPrOpenedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Most recent issue</span>
                <p class="font-semibold">{{ repo.mostRecentIssueOpenedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Oldest open issue</span>
                <p class="font-semibold">{{ repo.oldestOpenIssueOpenedAt }}</p>
              </div>
            </div>

            <!-- Dependencies -->
            <div class="p-4 flex-1">
              {% if repo.dependencies.length %}
              <div class="group space-y-2">
                <p class="text-sm">
                  {% if repo.dependencies.length === 1 %}
                  <span class="font-bold">1</span> dependency:
                  {% else %}
                  <span class="font-bold">{{ repo.dependencies.length }}</span> dependencies:
                  {% endif %}
                  <label>
                    <input class="hidden" type="checkbox" />
                    <span class="text-xs bg-slate-600 text-white rounded-lg py-0.5 px-2 hidden group-has-[:checked]:inline">Hide</span>
                    <span class="text-xs bg-slate-600 text-white rounded-lg py-0.5 px-2 group-has-[:checked]:hidden">Show</span>
                  </label>
                </p>
                <ul class="space-y-1.5 hidden group-has-[:checked]:block">
                  {% for dependency in repo.dependencies %}
                  <li>
                    <div class="inline-block whitespace-nowrap text-[0px]">
                      <span>
                        <span class="font-mono text-sm bg-{{ dependency.color }}-200 dark:bg-{{ dependency.color }}-800 rounded-l-full last:rounded-r-full py-1 px-2">{{ dependency.name }}</span>
                        {% if dependency.version %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-300 dark:bg-{{ dependency.color }}-900 last:rounded-r-full py-1 px-2">v{{ dependency.version }}</span>
                        {% endif %}
                        {% if dependency.tag %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-400 dark:bg-{{ dependency.color }}-950 text-white last:rounded-r-full py-1 px-2">{{ dependency.tag }}</span>
                        {% endif %}
                      </span>
                      <span class="inline-block w-1"></span>
                      <span>
                        {% if dependency.isOutdated %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-500 dark:bg-{{ dependency.color }}-600 text-white first:rounded-l-full last:rounded-r-full py-1 px-2">
                          <i class="align-[-1px] bx {{dependency.icon}}"></i>
                          {{ dependency.changelog }}
                          v{{ dependency.latestVersion }}
                        </span>
                        {% endif %}
                        {% if dependency.isEndOfLifeSoon %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-600 dark:bg-{{ dependency.color }}-700 text-white first:rounded-l-full last:rounded-r-full py-1 px-2">
                          <i class="align-[-1px] bx bxs-hourglass"></i>
                          <span class="font-sans">Support ends {{ dependency.endOfLifeRelative }}</span>
                        </span>
                        {% elif dependency.isOutOfSupport %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-600 dark:bg-{{ dependency.color }}-700 text-white first:rounded-l-full last:rounded-r-full py-1 px-2">
                          <i class="align-[-1px] bx bxs-hourglass-bottom"></i>
                          <span class="font-sans">Support ended {{ dependency.endOfLifeRelative }}</span>
                        </span>
                        {% endif %}
                      </span>
                    </div>
                  </li>
                  {% endfor %}
                </ul>
              </div>
              {% else %}
              <p class="text-slate-400 font-light italic text-sm">
                No dependencies have been discovered.
                <br/>
                Please make sure that Renovate has been configured on the repository to produce a dependency dashboard.
              </p>
              {% endif %}
            </div>

          </div>
          {% else %}
          <p class="col-span-full py-4 text-center text-slate-400 font-light italic">No repositories found.</p>
          {% endfor %}
        </div>
      </div>
    </div>
    <script>
      const toggle = document.getElementById('theme-toggle');
      const icon = document.getElementById('theme-icon');
      function applyTheme() {
        const isDark = document.documentElement.classList.contains('dark');
        icon.className = 'bx text-2xl ' + (isDark ? 'bx-sun' : 'bx-moon');
      }
      applyTheme();
      toggle.addEventListener('click', () => {
        document.documentElement.classList.toggle('dark');
        localStorage.theme = document.documentElement.classList.contains('dark') ? 'dark' : 'light';
        applyTheme();
      });
    </script>
  </body>
</html>

{% import "./macros.njk" as macros %}

<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <meta http-equiv="X-UA-Compatible" content="IE=edge" />
    <title>Towtruck</title>
    <meta name="description" content="" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <link href='https://unpkg.com/boxicons@2.1.4/css/boxicons.min.css' rel='stylesheet'>
    <script src="https://cdn.tailwindcss.com"></script>
    <script>tailwind.config = { darkMode: 'class' }</script>
    <script>
      if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        document.documentElement.classList.add('dark');
      }
    </script>
  </head>
  <body class="bg-slate-200 text-slate-900 dark:bg-slate-950 dark:text-slate-100">
    <header class="bg-slate-600 dark:bg-slate-900 text-white">
      <nav class="w-full flex items-center gap-4 p-6 border-b-4 border-slate-700 dark:border-slate-950">
        <a href="/" class="text-slate-300 hover:text-white transition-colors" aria-label="Back to home">
          <i class="bx bx-arrow-back text-2xl"></i>
        </a>
        <h1 class="text-3xl font-bold flex-1">Towtruck</h1>
        <button id="theme-toggle" aria-label="Toggle dark mode"
          class="text-slate-200 hover:text-white transition-colors p-1 rounded-lg hover:bg-slate-500 dark:hover:bg-slate-700">
          <i id="theme-icon" class="bx text-2xl"></i>
        </button>
      </nav>
    </header>

    <div class="container mx-auto flex flex-col mt-6 space-y-6">
      <div class="bg-slate-100 dark:bg-slate-900 rounded-lg border-b-4 border-slate-300 dark:border-slate-950 space-y-4">
        <h2 class="bg-slate-50 dark:bg-slate-800 rounded-t-lg border-b-2 border-slate-200 dark:border-slate-900 text-xl font-bold p-4">{{ org }}</h2>
        <p class="mx-4">
          {% if totalRepos === 1 %}
          There is <span class="font-bold">1</span> repository
          {% else %} 
          There are <span class="font-bold">{{ totalRepos }}</span> repositories
          {% endif %}
          that Towtruck is tracking for <span class="font-bold">{{ org }}</span>.
        </p>

        <!-- Alert filter and sort toolbar -->
        <div class="mx-4 pb-2">
          <div class="flex flex-wrap items-center gap-2">
            <span class="text-sm font-medium text-slate-500 dark:text-slate-400 mr-1">Filter alerts:</span>

            <!-- Critical alerts filter and sort -->
            <div class="flex gap-2">
              {% set criticalParams = "/" + org + "?alertFilter=criticalOnly" %}
              {% if sortBy %}{% set criticalParams = criticalParams + "&sortBy=" + sortBy %}{% endif %}
              {% if sortDirection %}{% set criticalParams = criticalParams + "&sortDirection=" + sortDirection %}{% endif %}
              {% if tag %}{% set criticalParams = criticalParams + "&tag=" + tag %}{% endif %}
              <a href="{{ criticalParams }}" class="inline-flex items-center rounded-full border px-3 py-1 text-sm font-medium transition-colors {% if alertFilter === 'criticalOnly' %}bg-red-700 text-white border-red-700 dark:bg-red-600 dark:border-red-600{% else %}bg-red-200 text-red-700 border-red-400 hover:bg-red-300 dark:bg-red-950 dark:text-red-300 dark:border-red-800 dark:hover:bg-red-900{% endif %}">
                Critical only
              </a>
              {{macros.sortableCardHeader("Critical alerts", "criticalSeverityAlerts", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            </div>

            <!-- Any alerts filter and sort -->
            <div class="flex gap-2">
              {% set anyAlertsParams = "/" + org + "?alertFilter=anyAlerts" %}
              {% if sortBy %}{% set anyAlertsParams = anyAlertsParams + "&sortBy=" + sortBy %}{% endif %}
              {% if sortDirection %}{% set anyAlertsParams = anyAlertsParams + "&sortDirection=" + sortDirection %}{% endif %}
              {% if tag %}{% set anyAlertsParams = anyAlertsParams + "&tag=" + tag %}{% endif %}
              <a href="{{ anyAlertsParams }}" class="inline-flex items-center rounded-full border px-3 py-1 text-sm font-medium transition-colors {% if alertFilter === 'anyAlerts' %}bg-yellow-600 text-white border-yellow-600 dark:bg-yellow-500 dark:border-yellow-500{% else %}bg-yellow-200 text-yellow-700 border-yellow-400 hover:bg-yellow-300 dark:bg-yellow-950 dark:text-yellow-300 dark:border-yellow-800 dark:hover:bg-yellow-900{% endif %}">
                Any alerts
              </a>
              {{macros.sortableCardHeader("Total alerts", "totalOpenAlerts", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            </div>

            <!-- Reset button -->
            <a href="{{"/" + org}}" class="inline-flex items-center rounded-full border px-3 py-1 text-sm font-medium transition-colors bg-slate-200 text-slate-700 border-slate-400 hover:bg-slate-300 dark:bg-slate-800 dark:text-slate-200 dark:border-slate-600 dark:hover:bg-slate-700">
              Reset
            </a>
          </div>
        </div>

        <!-- Sort toolbar -->
        <div class="mx-4 pb-2">
          <div class="flex flex-wrap items-center gap-2">
            <span class="text-sm font-medium text-slate-500 dark:text-slate-400 mr-1">Sort by:</span>
            {{macros.sortableCardHeader("Open issues", "openIssues", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Open bot PRs", "openBotPrCount", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Open PRs", "openPrCount", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Updated at", "updatedAt", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Most recent PR", "mostRecentPrOpenedAt", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Oldest open PR", "oldestOpenPrOpenedAt", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Most recent issue", "mostRecentIssueOpenedAt", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
            {{macros.sortableCardHeader("Oldest open issue", "oldestOpenIssueOpenedAt", sortDirection, sortBy, "/" + org, alertFilter, tag)}}
          </div>
        </div>

        <!-- Card grid -->
        <div class="mx-4 mb-6 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {% for repo in repos %}
          <div class="bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 flex flex-col shadow-sm">

            <!-- Card header -->
            <div class="p-4 border-b border-slate-100 dark:border-slate-700">
              <div class="flex flex-wrap items-center gap-2">
                <a target="_blank" class="text-lg font-semibold text-slate-600 dark:text-slate-300 hover:underline" href="{{repo.htmlUrl}}">{{ repo.name }}</a>
                {% if repo.language %}
                <span class="text-xs text-{{ repo.languageColor }}-600 dark:text-{{ repo.languageColor }}-400 border-{{ repo.languageColor }}-600 dark:border-{{ repo.languageColor }}-400 border rounded-lg py-0.5 px-2">{{ repo.language }}</span>
                {% endif %}
              </div>

              {% if repo.totalOpenAlerts !== undefined %}
              <div class="flex flex-wrap gap-0 mt-2 text-[0px]">
                {% set id = [repo.name, "alerts", "critical"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.criticalSeverityAlerts, ">", repo.criticalSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-red-600 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "Critical severity alerts")}}</div>
                {% set id = [repo.name, "alerts", "high"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.highSeverityAlerts, ">", repo.highSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-red-500 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "High severity alerts")}}</div>
                {% set id = [repo.name, "alerts", "medium"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.mediumSeverityAlerts, ">", repo.mediumSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-orange-500 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "Medium severity alerts")}}</div>
                {% set id = [repo.name, "alerts", "low"] | join("-") %}
                {% set mainText = ["<span", " class='font-bold'" if repo.lowSeverityAlerts, ">", repo.lowSeverityAlerts, "</span>"] | join('') | safe %}
                <div class="inline-block text-sm text-white bg-amber-500 first:rounded-l-full last:rounded-r-full first:pl-3 last:pr-3 py-1 px-2">{{macros.tooltip(id, mainText, "Low severity alerts")}}</div>
              </div>
              {% else %}
              <p class="mt-1 text-slate-400 text-xs font-light italic">Dependabot alerts disabled</p>
              {% endif %}

              {% if repo.description %}
              <p class="mt-2 text-sm text-slate-700 dark:text-slate-200">{{ repo.description }}</p>
              {% endif %}

              {% if repo.topics.length %}
              <div class="mt-2 flex flex-wrap gap-1">
                {% for topic in repo.topics %}
                <span class="text-xs text-slate-600 dark:text-slate-300 bg-slate-200 dark:bg-slate-900 rounded-full py-0.5 px-2">{{ topic }}</span>
                {% endfor %}
              </div>
              {% endif %}
            </div>

            <!-- Stats grid -->
            <div class="grid grid-cols-2 gap-x-4 gap-y-2 p-4 text-sm border-b border-slate-100 dark:border-slate-700">
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Open issues</span>
                <p class="font-semibold">{{ repo.openIssues }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Open PRs</span>
                <p class="font-semibold">{{ repo.openPrCount }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Bot PRs</span>
                <p class="font-semibold">{{ repo.openBotPrCount }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Updated at</span>
                <p class="font-semibold">{{ repo.updatedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Most recent PR</span>
                <p class="font-semibold">{{ repo.mostRecentPrOpenedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Oldest open PR</span>
                <p class="font-semibold">{{ repo.oldestOpenPrOpenedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Most recent issue</span>
                <p class="font-semibold">{{ repo.mostRecentIssueOpenedAt }}</p>
              </div>
              <div>
                <span class="text-slate-400 dark:text-slate-400 text-xs uppercase tracking-wide">Oldest open issue</span>
                <p class="font-semibold">{{ repo.oldestOpenIssueOpenedAt }}</p>
              </div>
            </div>

            <!-- Dependencies -->
            <div class="p-4 flex-1">
              {% if repo.dependencies.length %}
              <div class="group space-y-2">
                <p class="text-sm">
                  {% if repo.dependencies.length === 1 %}
                  <span class="font-bold">1</span> dependency:
                  {% else %}
                  <span class="font-bold">{{ repo.dependencies.length }}</span> dependencies:
                  {% endif %}
                  <label>
                    <input class="hidden" type="checkbox" />
                    <span class="text-xs bg-slate-600 text-white rounded-lg py-0.5 px-2 hidden group-has-[:checked]:inline">Hide</span>
                    <span class="text-xs bg-slate-600 text-white rounded-lg py-0.5 px-2 group-has-[:checked]:hidden">Show</span>
                  </label>
                </p>
                <ul class="space-y-1.5 hidden group-has-[:checked]:block">
                  {% for dependency in repo.dependencies %}
                  <li>
                    <div class="inline-block whitespace-nowrap text-[0px]">
                      <span>
                        <span class="font-mono text-sm bg-{{ dependency.color }}-200 dark:bg-{{ dependency.color }}-800 rounded-l-full last:rounded-r-full py-1 px-2">{{ dependency.name }}</span>
                        {% if dependency.version %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-300 dark:bg-{{ dependency.color }}-900 last:rounded-r-full py-1 px-2">v{{ dependency.version }}</span>
                        {% endif %}
                        {% if dependency.tag %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-400 dark:bg-{{ dependency.color }}-950 text-white last:rounded-r-full py-1 px-2">{{ dependency.tag }}</span>
                        {% endif %}
                      </span>
                      <span class="inline-block w-1"></span>
                      <span>
                        {% if dependency.isOutdated %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-500 dark:bg-{{ dependency.color }}-600 text-white first:rounded-l-full last:rounded-r-full py-1 px-2">
                          <i class="align-[-1px] bx {{dependency.icon}}"></i>
                          {{ dependency.changelog }}
                          v{{ dependency.latestVersion }}
                        </span>
                        {% endif %}
                        {% if dependency.isEndOfLifeSoon %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-600 dark:bg-{{ dependency.color }}-700 text-white first:rounded-l-full last:rounded-r-full py-1 px-2">
                          <i class="align-[-1px] bx bxs-hourglass"></i>
                          <span class="font-sans">Support ends {{ dependency.endOfLifeRelative }}</span>
                        </span>
                        {% elif dependency.isOutOfSupport %}
                        <span class="font-mono text-sm bg-{{ dependency.color }}-600 dark:bg-{{ dependency.color }}-700 text-white first:rounded-l-full last:rounded-r-full py-1 px-2">
                          <i class="align-[-1px] bx bxs-hourglass-bottom"></i>
                          <span class="font-sans">Support ended {{ dependency.endOfLifeRelative }}</span>
                        </span>
                        {% endif %}
                      </span>
                    </div>
                  </li>
                  {% endfor %}
                </ul>
              </div>
              {% else %}
              <p class="text-slate-400 font-light italic text-sm">
                No dependencies have been discovered.
                <br/>
                Please make sure that Renovate has been configured on the repository to produce a dependency dashboard.
              </p>
              {% endif %}
            </div>

          </div>
          {% else %}
          <p class="col-span-full py-4 text-center text-slate-400 font-light italic">No repositories found.</p>
          {% endfor %}
        </div>

        <!-- Pagination -->
        {% if totalPages > 1 %}
        {{macros.pagination(currentPage, pageNumbers, totalPages, "/" + org, sortBy, sortDirection, tag)}}
        {% endif %}
      </div>
    </div>
    <script>
      const toggle = document.getElementById('theme-toggle');
      const icon = document.getElementById('theme-icon');
      function applyTheme() {
        const isDark = document.documentElement.classList.contains('dark');
        icon.className = 'bx text-2xl ' + (isDark ? 'bx-sun' : 'bx-moon');
      }
      applyTheme();
      toggle.addEventListener('click', () => {
        document.documentElement.classList.toggle('dark');
        localStorage.theme = document.documentElement.classList.contains('dark') ? 'dark' : 'light';
        applyTheme();
      });
    </script>
  </body>
</html>

