{% macro pagination(currentPage, pageNumbers, totalPages, basePath, sortBy, sortDirection, tag) %}
{% set basePath = basePath if basePath else "/" %}
<nav class="flex justify-center items-center gap-2 my-6" aria-label="Pagination">
  <!-- Previous button -->
  {% if currentPage > 1 %}
    {% set prevParams = basePath + "?page=" + (currentPage - 1) %}
    {% if sortBy %}{% set prevParams = prevParams + "&sortBy=" + sortBy %}{% endif %}
    {% if sortDirection %}{% set prevParams = prevParams + "&sortDirection=" + sortDirection %}{% endif %}
    {% if tag %}{% set prevParams = prevParams + "&tag=" + tag %}{% endif %}
    <a href="{{ prevParams }}" class="px-4 py-2 rounded-lg border border-slate-400 bg-slate-200 text-slate-700 hover:bg-slate-300 dark:bg-slate-800 dark:text-slate-200 dark:border-slate-600 dark:hover:bg-slate-700 transition-colors" aria-label="Previous page">
      <i class="bx bx-chevron-left"></i>
    </a>
  {% else %}
    <button disabled class="px-4 py-2 rounded-lg border border-slate-300 bg-slate-100 text-slate-400 dark:bg-slate-900 dark:text-slate-600 dark:border-slate-700 cursor-not-allowed" aria-label="Previous page">
      <i class="bx bx-chevron-left"></i>
    </button>
  {% endif %}

  <!-- Page numbers -->
  <div class="flex gap-1">
    {% for pageNum in pageNumbers %}
      {% if pageNum === currentPage %}
        <span class="px-3 py-2 rounded-lg border-2 border-slate-700 bg-slate-700 text-white dark:border-slate-200 dark:bg-slate-200 dark:text-slate-900 font-semibold" aria-current="page">
          {{ pageNum }}
        </span>
      {% else %}
        {% set pageParams = basePath + "?page=" + pageNum %}
        {% if sortBy %}{% set pageParams = pageParams + "&sortBy=" + sortBy %}{% endif %}
        {% if sortDirection %}{% set pageParams = pageParams + "&sortDirection=" + sortDirection %}{% endif %}
        {% if tag %}{% set pageParams = pageParams + "&tag=" + tag %}{% endif %}
        <a href="{{ pageParams }}" class="px-3 py-2 rounded-lg border border-slate-400 bg-slate-200 text-slate-700 hover:bg-slate-300 dark:bg-slate-800 dark:text-slate-200 dark:border-slate-600 dark:hover:bg-slate-700 transition-colors">
          {{ pageNum }}
        </a>
      {% endif %}
    {% endfor %}
  </div>

  <!-- Next button -->
  {% if currentPage < totalPages %}
    {% set nextParams = basePath + "?page=" + (currentPage + 1) %}
    {% if sortBy %}{% set nextParams = nextParams + "&sortBy=" + sortBy %}{% endif %}
    {% if sortDirection %}{% set nextParams = nextParams + "&sortDirection=" + sortDirection %}{% endif %}
    {% if tag %}{% set nextParams = nextParams + "&tag=" + tag %}{% endif %}
    <a href="{{ nextParams }}" class="px-4 py-2 rounded-lg border border-slate-400 bg-slate-200 text-slate-700 hover:bg-slate-300 dark:bg-slate-800 dark:text-slate-200 dark:border-slate-600 dark:hover:bg-slate-700 transition-colors" aria-label="Next page">
      <i class="bx bx-chevron-right"></i>
    </a>
  {% else %}
    <button disabled class="px-4 py-2 rounded-lg border border-slate-300 bg-slate-100 text-slate-400 dark:bg-slate-900 dark:text-slate-600 dark:border-slate-700 cursor-not-allowed" aria-label="Next page">
      <i class="bx bx-chevron-right"></i>
    </button>
  {% endif %}
</nav>
{% endmacro %}

/**
 * Filters repositories based on alert criteria
 * @param {Array} repos - Array of repository objects
 * @param {string} alertFilter - The alert filter to apply ('criticalOnly', 'anyAlerts', or falsy for no filter)
 * @returns {Array} Filtered repositories
 */
export function filterByAlerts(repos, alertFilter) {
  if (!alertFilter) return repos;

  if (alertFilter === "criticalOnly") {
    return repos.filter((repo) => repo.criticalSeverityAlerts && repo.criticalSeverityAlerts > 0);
  }

  if (alertFilter === "anyAlerts") {
    return repos.filter((repo) => repo.totalOpenAlerts && repo.totalOpenAlerts > 0);
  }

  return repos;
}

import { describe, it } from "node:test";
import assert from "node:assert";
import { filterByAlerts } from "./alertFiltering.js";

describe("filterByAlerts", () => {
  const repos = [
    { name: "repo1", criticalSeverityAlerts: 2, totalOpenAlerts: 5 },
    { name: "repo2", criticalSeverityAlerts: 0, totalOpenAlerts: 3 },
    { name: "repo3", criticalSeverityAlerts: 1, totalOpenAlerts: 1 },
    { name: "repo4", criticalSeverityAlerts: 0, totalOpenAlerts: 0 },
  ];

  it("returns all repos when no filter is provided", () => {
    const result = filterByAlerts(repos, null);
    assert.strictEqual(result.length, 4);
    assert.deepStrictEqual(result, repos);
  });

  it("returns all repos when empty string filter is provided", () => {
    const result = filterByAlerts(repos, "");
    assert.strictEqual(result.length, 4);
  });

  it("filters repos with critical alerts only", () => {
    const result = filterByAlerts(repos, "criticalOnly");
    assert.strictEqual(result.length, 2);
    assert.strictEqual(result[0].name, "repo1");
    assert.strictEqual(result[1].name, "repo3");
  });

  it("filters repos with any open alerts", () => {
    const result = filterByAlerts(repos, "anyAlerts");
    assert.strictEqual(result.length, 3);
    assert.strictEqual(result[0].name, "repo1");
    assert.strictEqual(result[1].name, "repo2");
    assert.strictEqual(result[2].name, "repo3");
  });

  it("returns empty array when filtering by critical alerts and none exist", () => {
    const reposNoCritical = [
      { name: "repo1", criticalSeverityAlerts: 0, totalOpenAlerts: 2 },
      { name: "repo2", criticalSeverityAlerts: 0, totalOpenAlerts: 1 },
    ];
    const result = filterByAlerts(reposNoCritical, "criticalOnly");
    assert.strictEqual(result.length, 0);
  });

  it("returns empty array when filtering by any alerts and none exist", () => {
    const reposNoAlerts = [
      { name: "repo1", criticalSeverityAlerts: 0, totalOpenAlerts: 0 },
      { name: "repo2", criticalSeverityAlerts: 0, totalOpenAlerts: 0 },
    ];
    const result = filterByAlerts(reposNoAlerts, "anyAlerts");
    assert.strictEqual(result.length, 0);
  });

  it("returns empty array for unknown filter type", () => {
    const result = filterByAlerts(repos, "unknown");
    assert.strictEqual(result.length, 4);
  });

  it("handles repos without alert properties", () => {
    const reposWithout = [
      { name: "repo1" },
      { name: "repo2", criticalSeverityAlerts: 1 },
    ];
    const result = filterByAlerts(reposWithout, "criticalOnly");
    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].name, "repo2");
  });
});

const PAGE_SIZE = 5;

/**
 * Calculates pagination data for a given page
 * @param {Array} items - The array of items to paginate
 * @param {number} page - The current page number (1-indexed)
 * @returns {Object} Pagination data including paginated items, total pages, and page numbers to display
 */
export function calculatePagination(items, page = 1) {
  const validPage = Math.max(1, parseInt(page) || 1);
  let totalPages = Math.ceil(items.length / PAGE_SIZE);
  if (totalPages === 0) {
    totalPages = 1;
  }
  const validPageNumber = Math.min(validPage, totalPages);

  const startIndex = (validPageNumber - 1) * PAGE_SIZE;
  const paginatedItems = items.slice(startIndex, startIndex + PAGE_SIZE);

  // Calculate page numbers to display (current ± 2)
  const pageNumbers = [];
  for (let i = Math.max(1, validPageNumber - 2); i <= Math.min(totalPages, validPageNumber + 2); i++) {
    pageNumbers.push(i);
  }

  return {
    items: paginatedItems,
    currentPage: validPageNumber,
    totalPages: totalPages,
    pageNumbers,
    hasPreviousPage: validPageNumber > 1,
    hasNextPage: validPageNumber < totalPages,
    pageSize: PAGE_SIZE,
  };
}

export { PAGE_SIZE };

import { describe, it } from "node:test";
import assert from "node:assert";
import { calculatePagination, PAGE_SIZE } from "./pagination.js";

describe("calculatePagination", () => {
  it("returns the first page when no page parameter is provided", () => {
    const items = Array.from({ length: 12 }, (_, i) => i + 1);
    const result = calculatePagination(items);

    assert.deepStrictEqual(result.items, [1, 2, 3, 4, 5]);
    assert.strictEqual(result.currentPage, 1);
    assert.strictEqual(result.totalPages, 3);
    assert.strictEqual(result.hasPreviousPage, false);
    assert.strictEqual(result.hasNextPage, true);
  });

  it("returns the correct page when a valid page number is provided", () => {
    const items = Array.from({ length: 12 }, (_, i) => i + 1);
    const result = calculatePagination(items, 2);

    assert.deepStrictEqual(result.items, [6, 7, 8, 9, 10]);
    assert.strictEqual(result.currentPage, 2);
    assert.strictEqual(result.totalPages, 3);
    assert.strictEqual(result.hasPreviousPage, true);
    assert.strictEqual(result.hasNextPage, true);
  });

  it("returns the last page when requesting a page beyond the total", () => {
    const items = Array.from({ length: 12 }, (_, i) => i + 1);
    const result = calculatePagination(items, 10);

    assert.deepStrictEqual(result.items, [11, 12]);
    assert.strictEqual(result.currentPage, 3);
    assert.strictEqual(result.totalPages, 3);
    assert.strictEqual(result.hasPreviousPage, true);
    assert.strictEqual(result.hasNextPage, false);
  });

  it("returns page 1 when given a negative page number", () => {
    const items = Array.from({ length: 12 }, (_, i) => i + 1);
    const result = calculatePagination(items, -5);

    assert.deepStrictEqual(result.items, [1, 2, 3, 4, 5]);
    assert.strictEqual(result.currentPage, 1);
    assert.strictEqual(result.hasPreviousPage, false);
  });

  it("correctly calculates page numbers to display (current page ± 2)", () => {
    const items = Array.from({ length: 30 }, (_, i) => i + 1);

    // Page 1: should show [1, 2, 3]
    let result = calculatePagination(items, 1);
    assert.deepStrictEqual(result.pageNumbers, [1, 2, 3]);

    // Page 3: should show [1, 2, 3, 4, 5]
    result = calculatePagination(items, 3);
    assert.deepStrictEqual(result.pageNumbers, [1, 2, 3, 4, 5]);

    // Page 5: should show [3, 4, 5, 6]
    result = calculatePagination(items, 5);
    assert.deepStrictEqual(result.pageNumbers, [3, 4, 5, 6]);

    // Last page (6): should show [4, 5, 6]
    result = calculatePagination(items, 6);
    assert.deepStrictEqual(result.pageNumbers, [4, 5, 6]);
  });

  it("handles empty arrays", () => {
    const result = calculatePagination([], 1);

    assert.deepStrictEqual(result.items, []);
    assert.strictEqual(result.currentPage, 1);
    assert.strictEqual(result.totalPages, 1);
    assert.deepStrictEqual(result.pageNumbers, [1]);
    assert.strictEqual(result.hasPreviousPage, false);
    assert.strictEqual(result.hasNextPage, false);
  });

  it("handles single page of items", () => {
    const items = Array.from({ length: 3 }, (_, i) => i + 1);
    const result = calculatePagination(items);

    assert.deepStrictEqual(result.items, [1, 2, 3]);
    assert.strictEqual(result.currentPage, 1);
    assert.strictEqual(result.totalPages, 1);
    assert.strictEqual(result.hasPreviousPage, false);
    assert.strictEqual(result.hasNextPage, false);
  });

  it("handles exactly one page worth of items", () => {
    const items = Array.from({ length: PAGE_SIZE }, (_, i) => i + 1);
    const result = calculatePagination(items);

    assert.deepStrictEqual(result.items, Array.from({ length: PAGE_SIZE }, (_, i) => i + 1));
    assert.strictEqual(result.currentPage, 1);
    assert.strictEqual(result.totalPages, 1);
    assert.strictEqual(result.hasNextPage, false);
  });

  it("handles non-numeric page parameter", () => {
    const items = Array.from({ length: 12 }, (_, i) => i + 1);
    const result = calculatePagination(items, "abc");

    assert.deepStrictEqual(result.items, [1, 2, 3, 4, 5]);
    assert.strictEqual(result.currentPage, 1);
  });

  it("handles string page numbers", () => {
    const items = Array.from({ length: 12 }, (_, i) => i + 1);
    const result = calculatePagination(items, "2");

    assert.deepStrictEqual(result.items, [6, 7, 8, 9, 10]);
    assert.strictEqual(result.currentPage, 2);
  });

  it("returns correct total pages calculation", () => {
    // 11 items should give 3 pages (5 + 5 + 1)
    let result = calculatePagination(Array.from({ length: 11 }, (_, i) => i + 1));
    assert.strictEqual(result.totalPages, 3);

    // 5 items should give 1 page
    result = calculatePagination(Array.from({ length: 5 }, (_, i) => i + 1));
    assert.strictEqual(result.totalPages, 1);

    // 6 items should give 2 pages (5 + 1)
    result = calculatePagination(Array.from({ length: 6 }, (_, i) => i + 1));
    assert.strictEqual(result.totalPages, 2);
  });
});

/**
 * @typedef {string} SortDirection
 * @enum {SortDirection}
 * @property {"asc"} ASC
 * @property {"desc"} DESC
 */
/**
 * @typedef {import('./index').UiRepo} UiRepo
 */

/**
 * Sorts repos by the a numeric value
 * @param {UiRepo[]} repos
 * @param {SortDirection} sortDirection
 * @param {string} key - The key to sort by
 * @returns {UiRepo[]}
 */
export const sortByNumericValue = (repos, sortDirection, key) => {
  if (!sortDirection) return repos;
  if (sortDirection === "asc") {
    return repos.sort((a, b) => a[key] - b[key]);
  }
  return repos.sort((a, b) => b[key] - a[key]);
};

/**
 * Compares two strings in lexicographical order.
 * @param {string?} first 
 * @param {string?} second 
 * @returns {number}
 */
const lexicographicalSort = (first, second, ascending) => {
  if (!first) return 1;
  if (!second) return -1;

  if (ascending) return first.localeCompare(second);
  return second.localeCompare(first);
}

/**
 * Sorts repos by a timestamp value in ISO 8601 (`YYYY-MM-DDThh:mm:ssZ`) format
 * @param {UiRepo[]} repos 
 * @param {SortDirection} sortDirection 
 * @param {string} key 
 * @returns {UiRepo[]}
 */
export const sortByISO8601Timestamp = (repos, sortDirection, key) => {
  if (!sortDirection) return repos;

  return repos.sort((a, b) => lexicographicalSort(a[key], b[key], sortDirection === "asc"));
}

/**
 * Sorts repositories based on the specified type and direction.
 * @param {"openPrCount"|"openBotPrCount"|"openIssues"|} sortBy - The type of sorting to apply, either by open PRs count or open issues.
 * @param {SortDirection} sortDirection - The direction to sort, either "asc" for ascending or "desc" for descending.
 * @param {UiRepo[]} repos - An array of repository objects to sort.
 * @returns {UiRepo[]} The sorted array of repository objects.
 */
export const sortByType = (repos, sortDirection, sortBy) => {
  switch (sortBy) {
    case "openPrCount":
      return sortByNumericValue(repos, sortDirection, "openPrCount");

    case "openBotPrCount":
      return sortByNumericValue(repos, sortDirection, "openBotPrCount");

    case "openIssues":
      return sortByNumericValue(repos, sortDirection, "openIssues");

    case "updatedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "updatedAtISO8601");

    case "mostRecentPrOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "mostRecentPrOpenedAtISO8601");

    case "oldestOpenPrOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "oldestOpenPrOpenedAtISO8601");

    case "mostRecentIssueOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "mostRecentIssueOpenedAtISO8601");

    case "oldestOpenIssueOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "oldestOpenIssueOpenedAtISO8601");

    default:
      return repos;
  }
};

/**
 * @typedef {string} SortDirection
 * @enum {SortDirection}
 * @property {"asc"} ASC
 * @property {"desc"} DESC
 */
/**
 * @typedef {import('./index').UiRepo} UiRepo
 */

/**
 * Sorts repos by the a numeric value
 * @param {UiRepo[]} repos
 * @param {SortDirection} sortDirection
 * @param {string} key - The key to sort by
 * @returns {UiRepo[]}
 */
export const sortByNumericValue = (repos, sortDirection, key) => {
  if (!sortDirection) return repos;
  if (sortDirection === "asc") {
    return repos.sort((a, b) => a[key] - b[key]);
  }
  return repos.sort((a, b) => b[key] - a[key]);
};

/**
 * Compares two strings in lexicographical order.
 * @param {string?} first 
 * @param {string?} second 
 * @returns {number}
 */
const lexicographicalSort = (first, second, ascending) => {
  if (!first) return 1;
  if (!second) return -1;

  if (ascending) return first.localeCompare(second);
  return second.localeCompare(first);
}

/**
 * Sorts repos by a timestamp value in ISO 8601 (`YYYY-MM-DDThh:mm:ssZ`) format
 * @param {UiRepo[]} repos 
 * @param {SortDirection} sortDirection 
 * @param {string} key 
 * @returns {UiRepo[]}
 */
export const sortByISO8601Timestamp = (repos, sortDirection, key) => {
  if (!sortDirection) return repos;

  return repos.sort((a, b) => lexicographicalSort(a[key], b[key], sortDirection === "asc"));
}

/**
 * Sorts repositories based on the specified type and direction.
 * @param {"openPrCount"|"openBotPrCount"|"openIssues"|} sortBy - The type of sorting to apply, either by open PRs count or open issues.
 * @param {SortDirection} sortDirection - The direction to sort, either "asc" for ascending or "desc" for descending.
 * @param {UiRepo[]} repos - An array of repository objects to sort.
 * @returns {UiRepo[]} The sorted array of repository objects.
 */
export const sortByType = (repos, sortDirection, sortBy) => {
  switch (sortBy) {
    case "openPrCount":
      return sortByNumericValue(repos, sortDirection, "openPrCount");

    case "openBotPrCount":
      return sortByNumericValue(repos, sortDirection, "openBotPrCount");

    case "openIssues":
      return sortByNumericValue(repos, sortDirection, "openIssues");

    case "updatedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "updatedAtISO8601");

    case "mostRecentPrOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "mostRecentPrOpenedAtISO8601");

    case "oldestOpenPrOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "oldestOpenPrOpenedAtISO8601");

    case "mostRecentIssueOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "mostRecentIssueOpenedAtISO8601");

    case "oldestOpenIssueOpenedAt":
      return sortByISO8601Timestamp(repos, sortDirection, "oldestOpenIssueOpenedAtISO8601");

    case "criticalSeverityAlerts":
      return sortByNumericValue(repos, sortDirection, "criticalSeverityAlerts");

    case "totalOpenAlerts":
      return sortByNumericValue(repos, sortDirection, "totalOpenAlerts");

    default:
      return repos;
  }
};
